def _cell_float(value):
    if value is None:
        return 0.0
    s = str(value).strip()
    if s == "" or s.lower() == "nan":
        return 0.0
    try:
        return float(s)
    except ValueError:
        return 0.0


def _d2_7(q7, t7):
    s = 0.0
    for j in range(7):
        d = q7[j] - t7[j]
        s += d * d
    return s


def _majority_vote(neighbor_labels):
    counts = Counter(neighbor_labels)
    top = max(counts.values())
    tied = [lab for lab, c in counts.items() if c == top]
    return min(tied, key=lambda lab: _CLASS_ORDER.index(lab))


def predict(row):
    """One row: dict-like keyed by CSV headers (e.g. DictReader)."""
    if NEIGHBOR_WEIGHTS != "uniform":
        raise NotImplementedError(
            "pred_knn only implements NEIGHBOR_WEIGHTS='uniform'; "
            "use project_knn_all.py with sklearn for distance weights."
        )
    q7 = tuple(_cell_float(row.get(name)) for name in _FEATURE_NAMES)
    dists = []
    for i, rec in enumerate(_TRAIN):
        t7 = rec[:-1]
        lab = rec[-1]
        d2 = _d2_7(q7, t7)
        dists.append((d2, i, lab))
    dists.sort(key=lambda t: (t[0], t[1]))
    k_nearest = [lab for _, _, lab in dists[:K]]
    return _majority_vote(k_nearest)


def predict_all(filename):
    with open(filename, newline="", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        rows = list(reader)
    return [predict(row) for row in rows]


if __name__ == "__main__":
    import sys

    if len(sys.argv) < 2:
        print("Usage: python pred_knn.py <file.csv>", file=sys.stderr)
        sys.exit(1)
    preds = predict_all(sys.argv[1])
    print(len(preds), "predictions")
